function sortColors(nums) {

    let left = 0, i = 0, right = nums.length-1;

    while(i <= right) {
        if(nums[i] === 0) {
            swap(nums, i, left);
            left++;
            i++;
        } else if(nums[i] === 2) {
            swap(nums, i, right);
            right--;
        } else {
            i++;
        }
    }

    return nums;
}

function swap(nums, one, two) {
    [nums[one], nums[two]] = [nums[two], nums[one]];
}

