function findOddNumberObj(nums) {
    const freqObj = {};

    for(const num of nums) {
        freqObj[num] = (freqObj[num] || 0) + 1;
    }

    for(const [key, value] of Object.entries(freqObj)) {
        if(value%2 !== 0) {
            return parseInt(key);
        }
    }

    return null;
}

