function countTriangles(numbers) {
    numbers.sort((a, b) => a - b);
    const length = numbers.length;

    let count = 0;

    for(let i = 0; i < length-2; i++) {
        let k = i + 2;
        for(let j = i + 1; j < length-1; j++) {
            while(k < length && numbers[i] + numbers[j] > numbers[k]) {
                k++;
            }

            count += k-j-1;
        }
    }

    return count;
}

