function absDistinct(numbers) {
    numbers.sort((a, b) => a - b);
    const seen = new Set();

    let left = 0, right = numbers.length - 1;

    while(left <= right) {
        const leftAbs = Math.abs(numbers[left]);
        const rightAbs = Math.abs(numbers[right]);

        if(leftAbs > rightAbs) {
            seen.add(leftAbs);
            left++;
        } else {
            seen.add(rightAbs);
            right--;
        }
    }

    return seen.size;
}

